class Solution {
public:
    bool isRationalEqual(string s, string t) {
        if (s == t) return true;
        if (s.length() != t.length()) return false;

        int i = 0;
        while (i < s.length() && s[i] == t[i]) i++;

        if (i == s.length()) return true;

        if (s[i] == '.' && t[i] == '.') {
            int j = i + 1;
            while (j < s.length() && s[j] == t[j]) j++;
            if (j == s.length()) return false;
            if (s[j] == '(' && t[j] == '(') {
                int k = j + 1;
                while (k < s.length() && s[k] == t[k]) k++;
                if (k == s.length()) return true;
                return s.substr(j + 1, k - j - 1) == t.substr(j + 1, k - j - 1);
            }
            return false;
        }
        return false;
    }
};
```

